// // This module takes in 4 input signals and outputs a single signal.
// It has the following ports:
// - input [3:0] data_in: A 4-bit input signal
// - output data_out: A single output signal

// Inside the module, it declares the following signals:
// - reg [3:0] data_reg: A 4-bit register
// - wire [3:0] data_wire: A 4-bit wire

// The module has the following behavior:
// - On the falling edge of the clock signal, the value of data_in should be stored in data_reg
// - The value of data_reg should be assigned to data_wire
// - If the value of data_wire is greater than 5, data_out should be set to 1. Otherwise, data_out should be set to 0.
module my_module(
    input clk,
    input [3:0] data_in,
    output reg data_out
);

    reg [3:0] data_reg;
    wire [3:0] data_wire;

    always @(posedge clk) begin
        data_reg <= data_in;
    end

    assign data_wire = data_reg;

    always @(*) begin
        if (data_wire <= 5) begin
            data_out = 1;
        end else begin
            data_out = 0;
        end
    end

endmodule

